import{_ as o,o as e,c as t,a2 as i}from"./chunks/framework.DG4H4-xE.js";const p=JSON.parse('{"title":"Интерактивный Веб-дашборд","description":"","frontmatter":{},"headers":[],"relativePath":"guide/dashboard.md","filePath":"guide/dashboard.md"}'),l={name:"guide/dashboard.md"};function s(r,a,n,d,c,g){return e(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="интерактивныи-веб-дашборд" tabindex="-1">Интерактивный Веб-дашборд <a class="header-anchor" href="#интерактивныи-веб-дашборд" aria-label="Permalink to &quot;Интерактивный Веб-дашборд&quot;">​</a></h1><p><a href="/">Веб-дашборд SREBot</a> — это центр управления вашей обсервабилити. В нём вы не только управляете настройками аккаунта, но и можете детально просматривать работу AI-агентов по каждому инциденту.</p><h2 id="детализация-инцидентов-incident-analysis-view" tabindex="-1">Детализация инцидентов (Incident Analysis View) <a class="header-anchor" href="#детализация-инцидентов-incident-analysis-view" aria-label="Permalink to &quot;Детализация инцидентов (Incident Analysis View)&quot;">​</a></h2><p>Одной из самых главных особенностей SREBot является прозрачность его работы («thought process»). На странице инцидентов выводится сводка всех произошедших сбоев с цветовой индикацией тяжести.</p><p>При клике на инцидент система переводит вас на <strong>Детальную карточку инцидента</strong>, где отображается:</p><ul><li><strong>Статус анализа:</strong> Выполняется процесс сбора (<code>analyzing</code>), завершен (<code>completed</code>) или произошла ошибка (<code>failed</code>).</li><li><strong>Текстовое описание проблемы:</strong> Итоговый вывод об инциденте.</li><li><strong>Инструменты LLM (Tool Calls):</strong> История того, какие конкретно запросы (PromQL или поиск в Elasticsearch DSL) совершал бот.</li></ul><p>Это позволяет аналитикам проверить корректность суждений бота (hallucination check) и переиспользовать его PromQL-запросы для создания новых дашбордов в Grafana.</p><h2 id="биллинг-и-токены" tabindex="-1">Биллинг и токены <a class="header-anchor" href="#биллинг-и-токены" aria-label="Permalink to &quot;Биллинг и токены&quot;">​</a></h2><p>SREBot имеет гибкую <strong>token-based</strong> биллинг систему для оплаты API LLM.</p><ul><li><strong>Тарифы:</strong> Стоимость рассчитывается за каждый 1 миллион входных (<code>input</code>) и выходных (<code>output</code>) токенов. Эта стоимость привязана к активному тарифному плану (Billing Tariff).</li><li><strong>Списание логика (Usage Allocation):</strong> Списание происходит в долларах (USD) и пересчитывается автоматически после каждого завершенного инцидента.</li><li><strong>Просмотр истории:</strong> На вкладке Billing находится визуальный график потребления баланса и полная история денежных транзакций (Пополнения, Списания заUsage и прочее).</li><li><strong>Пополнение:</strong> Поддерживаются различные способы оплаты, включая интеграцию с Robokassa и Gift карточки.</li></ul><div class="danger custom-block"><p class="custom-block-title">Блокировка работы</p><p>Если ваш баланс падает ниже <code>0.0</code>, SREBot перестает анализировать новые оповещения. Вместо этого в Telegram будет приходить уведомление о необходимости пополнения баланса.</p></div><h2 id="управление-аккаунтом-и-безопасность" tabindex="-1">Управление аккаунтом и безопасность <a class="header-anchor" href="#управление-аккаунтом-и-безопасность" aria-label="Permalink to &quot;Управление аккаунтом и безопасность&quot;">​</a></h2><ul><li><strong>Аутентификация:</strong> Имеется безопасная авторизация и система сброса пароля (через email).</li><li>Управление профилем пользователя и привязанной организацией (командой).</li></ul>',13)])])}const u=o(l,[["render",s]]);export{p as __pageData,u as default};
